import java.util.ArrayList;
import java.util.Collections;

public class ArrayListExamples {
    public static void main(String[] args) {
        ArrayList<String> students = new ArrayList<>();
        students.add("Riya");
        students.add("Arjun");
        students.add("Meera");
        students.add("Kiran");
        students.add("Sneha");

        System.out.println("Original: " + students);
        System.out.println("Size: " + students.size());
        System.out.println("Index 2: " + students.get(2));

        students.set(1, "Arjun Kumar");
        students.remove("Kiran");

        Collections.sort(students);
        System.out.println("Sorted: " + students);

        String target = "Meera";
        System.out.println("Contains " + target + "? " + students.contains(target));
        System.out.println("Index of " + target + ": " + students.indexOf(target));
    }
}

