import java.util.ArrayDeque;
import java.util.LinkedList;
import java.util.PriorityQueue;
import java.util.Queue;

public class QueueExamples {
    public static void main(String[] args) {
        Queue<String> ticketQueue = new LinkedList<>();
        ticketQueue.offer("Customer-1");
        ticketQueue.offer("Customer-2");
        ticketQueue.offer("Customer-3");

        System.out.println("=== Ticket Counter (FIFO) ===");
        while (!ticketQueue.isEmpty()) {
            System.out.println("Serving: " + ticketQueue.poll());
        }

        PriorityQueue<Integer> emergency = new PriorityQueue<>();
        emergency.offer(3);
        emergency.offer(1);
        emergency.offer(2);
        System.out.println("\n=== Priority Queue (lowest first) ===");
        while (!emergency.isEmpty()) {
            System.out.println("Next: " + emergency.poll());
        }

        ArrayDeque<String> stack = new ArrayDeque<>();
        stack.push("Page-1");
        stack.push("Page-2");
        stack.push("Page-3");
        System.out.println("\n=== Browser Back (Stack) ===");
        System.out.println("Back to: " + stack.pop());
        System.out.println("Back to: " + stack.pop());
    }
}

