import java.util.ArrayList;
import java.util.Collections;
import java.util.Comparator;
import java.util.List;

class Student implements Comparable<Student> {
    private final String name;
    private final int rollNumber;
    private final int marks;

    Student(String name, int rollNumber, int marks) {
        this.name = name;
        this.rollNumber = rollNumber;
        this.marks = marks;
    }

    String getName() { return name; }
    int getRollNumber() { return rollNumber; }
    int getMarks() { return marks; }

    @Override
    public int compareTo(Student other) {
        return Integer.compare(this.rollNumber, other.rollNumber);
    }

    @Override
    public String toString() {
        return rollNumber + ": " + name + " (" + marks + ")";
    }
}

public class ComparatorExamples {
    public static void main(String[] args) {
        List<Student> students = new ArrayList<>();
        students.add(new Student("Riya", 103, 92));
        students.add(new Student("Arjun", 101, 78));
        students.add(new Student("Meera", 102, 85));

        Collections.sort(students);
        System.out.println("By roll number: " + students);

        students.sort(Comparator.comparingInt(Student::getMarks).reversed());
        System.out.println("By marks (desc): " + students);

        students.sort((a, b) -> a.getName().compareTo(b.getName()));
        System.out.println("By name: " + students);
    }
}

