import java.util.ArrayList;
import java.util.Comparator;
import java.util.List;
import java.util.Optional;
import java.util.Scanner;

public class StudentManagementSystem {
    private final List<Student> students = new ArrayList<>();
    private final Scanner sc = new Scanner(System.in);

    public static void main(String[] args) {
        new StudentManagementSystem().run();
    }

    void run() {
        boolean running = true;
        while (running) {
            printMenu();
            switch (sc.nextLine().trim()) {
                case "1" -> addStudent();
                case "2" -> removeStudent();
                case "3" -> searchStudent();
                case "4" -> displayAll();
                case "5" -> sortByMarks();
                case "6" -> running = false;
                default -> System.out.println("Invalid option.");
            }
        }
        sc.close();
    }

    void addStudent() {
        System.out.print("Roll: "); int roll = Integer.parseInt(sc.nextLine());
        if (findByRoll(roll).isPresent()) {
            System.out.println("Roll " + roll + " already exists.");
            return;
        }
        System.out.print("Name: "); String name = sc.nextLine();
        System.out.print("Branch: "); String branch = sc.nextLine();
        System.out.print("Marks: "); int marks = Integer.parseInt(sc.nextLine());
        students.add(new Student(roll, name, branch, marks));
        System.out.println("Student added.");
    }

    void removeStudent() {
        System.out.print("Roll to remove: ");
        int roll = Integer.parseInt(sc.nextLine());
        findByRoll(roll).ifPresentOrElse(
            s -> { students.remove(s); System.out.println("Removed."); },
            () -> System.out.println("Not found.")
        );
    }

    void searchStudent() {
        System.out.print("Roll to search: ");
        int roll = Integer.parseInt(sc.nextLine());
        findByRoll(roll).ifPresentOrElse(
            System.out::println,
            () -> System.out.println("Not found.")
        );
    }

    void displayAll() {
        if (students.isEmpty()) System.out.println("No students.");
        else students.forEach(System.out::println);
    }

    void sortByMarks() {
        students.sort(Comparator.comparingInt(Student::marks).reversed());
        displayAll();
    }

    Optional<Student> findByRoll(int roll) {
        return students.stream().filter(s -> s.roll() == roll).findFirst();
    }

    void printMenu() {
        System.out.println("\n--- Student Management ---");
        System.out.println("1.Add 2.Remove 3.Search 4.Display 5.Sort 6.Exit");
        System.out.print("Choice: ");
    }

    record Student(int roll, String name, String branch, int marks) {
        @Override public String toString() {
            return roll + " | " + name + " | " + branch + " | " + marks;
        }
    }
}

