import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class ShoppingCart {
    private final Map<String, Product> catalog = new HashMap<>();
    private final List<CartItem> cart = new ArrayList<>();

    public ShoppingCart() {
        catalog.put("P001", new Product("P001", "Java Book", 599.0));
        catalog.put("P002", new Product("P002", "USB Drive", 499.0));
        catalog.put("P003", new Product("P003", "Mouse", 799.0));
    }

    public static void main(String[] args) {
        ShoppingCart cart = new ShoppingCart();
        cart.addToCart("P001", 2);
        cart.addToCart("P003", 1);
        cart.displayCart();
        System.out.printf("Grand Total: Rs. %.2f%n", cart.calculateTotal());
    }

    void addToCart(String id, int qty) {
        if (!catalog.containsKey(id) || qty <= 0) {
            System.out.println("Invalid product or quantity.");
            return;
        }
        cart.add(new CartItem(id, qty));
        System.out.println("Added " + qty + " x " + catalog.get(id).name());
    }

    void displayCart() {
        System.out.println("\n--- Cart ---");
        for (CartItem item : cart) {
            Product p = catalog.get(item.productId());
            double line = p.price() * item.quantity();
            System.out.printf("%s | Rs.%.2f x %d = Rs.%.2f%n",
                p.name(), p.price(), item.quantity(), line);
        }
    }

    double calculateTotal() {
        double total = 0;
        for (CartItem item : cart) {
            Product p = catalog.get(item.productId());
            total += p.price() * item.quantity();
        }
        return total;
    }

    record Product(String id, String name, double price) {}
    record CartItem(String productId, int quantity) {}
}

