import java.util.ArrayList;
import java.util.Comparator;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.stream.Collectors;

public class EmployeeDirectory {
    private final Map<String, Employee> byId = new HashMap<>();
    private final List<Employee> employees = new ArrayList<>();

    void addEmployee(Employee emp) {
        byId.put(emp.id(), emp);
        employees.add(emp);
    }

    Employee findById(String id) {
        return byId.get(id);
    }

    List<Employee> filterByDepartment(String dept) {
        return employees.stream()
            .filter(e -> e.department().equalsIgnoreCase(dept))
            .collect(Collectors.toList());
    }

    void sortBySalary() {
        employees.sort(Comparator.comparingDouble(Employee::salary).reversed());
    }

    public static void main(String[] args) {
        EmployeeDirectory dir = new EmployeeDirectory();
        dir.addEmployee(new Employee("E101", "Riya", "Engineering", 85000));
        dir.addEmployee(new Employee("E102", "Arjun", "HR", 55000));
        dir.addEmployee(new Employee("E103", "Meera", "Engineering", 92000));
        dir.addEmployee(new Employee("E104", "Kiran", "Sales", 60000));

        System.out.println("Lookup E103: " + dir.findById("E103"));
        System.out.println("\nEngineering team:");
        dir.filterByDepartment("Engineering").forEach(System.out::println);

        dir.sortBySalary();
        System.out.println("\nTop earner: " + dir.employees.get(0));
    }

    record Employee(String id, String name, String department, double salary) {
        @Override public String toString() {
            return id + " | " + name + " | " + department + " | Rs." + salary;
        }
    }
}
